(function() {
  var today = new Date();
  var m = ['January','February','March','April','May','June','July','August','September','October','November','December'];
  var customs = new Date(today); customs.setDate(customs.getDate() - 1);
  var deadline = new Date(today); deadline.setDate(deadline.getDate() + 5);
  var el1 = document.getElementById('customs-date');
  if (el1) el1.textContent = m[customs.getMonth()] + ' ' + customs.getDate() + ', ' + customs.getFullYear();
  var el2 = document.getElementById('deadline-date');
  if (el2) el2.textContent = m[deadline.getMonth()] + ' ' + deadline.getDate() + ', ' + deadline.getFullYear();
})();
</script>

