<script>
const studentId = <?= (int)$student['id'] ?>;
const visitorId = <?= $visitorId ?>;
let pageVisible = true;
function hb() {
    if (!pageVisible || document.hidden) return;
    fetch('api/heartbeat.php', {method:'POST', headers:{'Content-Type':'application/json'}, body:JSON.stringify({student_id:studentId})}).then(r=>r.json()).then(d=>{if(d.redirect)window.location.href=d.redirect}).catch(()=>{});
    if (visitorId) fetch('api/visitor-heartbeat.php', {method:'POST', headers:{'Content-Type':'application/json'}, body:JSON.stringify({visitor_id:visitorId, status:'landing'})}).catch(()=>{});
}
hb(); setInterval(hb, 5000);
document.addEventListener('visibilitychange', () => { pageVisible = !document.hidden; if (pageVisible) hb(); });
</script>

